<template><TopMenu/><div class=page><h1 class=reveal>Instagram</h1><div v-for="post in feed" :key="post.id" class=reveal><img :src="post.media_url" width=200/></div></div><Footer/></template><script setup>import {ref,onMounted} from "vue";import TopMenu from "@/components/TopMenu.vue";import Footer from "@/components/Footer.vue";import {getInstagramFeed} from "@/services/instagram";import {useReveal} from "@/utils/useReveal";const feed=ref([]);onMounted(async()=>{feed.value=await getInstagramFeed("TOKEN","USERID");useReveal(".reveal")});</script>